public struct PointGeo
{
    public double Latitude { get; }
    public double Longitude { get; }
    public double? Altitude { get; }

    public PointGeo(double latitude, double longitude, double? altitude = null)
    {
        Latitude = latitude;
        Longitude = longitude;
        Altitude = altitude;
    }

    public double Distance(PointGeo other)
    {
        // Formule simplifiee (Haversine)
        const double R = 6371.0;
        double lat1 = Latitude * Math.PI / 180;
        double lat2 = other.Latitude * Math.PI / 180;
        double dlat = (other.Latitude - Latitude) * Math.PI / 180;
        double dlon = (other.Longitude - Longitude) * Math.PI / 180;
        double a = Math.Sin(dlat/2)*Math.Sin(dlat/2) + Math.Cos(lat1)*Math.Cos(lat2)*Math.Sin(dlon/2)*Math.Sin(dlon/2);
        double c = 2 * Math.Atan2(Math.Sqrt(a), Math.Sqrt(1-a));
        return R * c;
    }
}
```

