public readonly struct Transaction
{
    public string Id { get; }
    public double Montant { get; }
    public DateTime Date { get; }
    public string Description { get; }

    public Transaction(string id, double montant, DateTime date, string description)
    {
        Id = id; Montant = montant; Date = date; Description = description;
    }

    public Transaction AppliquerRemise(double pourcentage) =>
        this with { Montant = Montant - Montant * pourcentage / 100 };
}
```

